# ================BUILDING (NEW,SURVEYED,RESURVEYED)========================================================== 	
	LAYER
		NAME 'BLD'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo 
		INCLUDE "datashare.inc"
		DATA "sp_geometry FROM (SELECT v.*
		FROM vw_att_details_building_map v
		INNER JOIN user_permission_area m 
        ON v.region_id = m.region_id 
        AND v.province_id = m.province_id 
        AND m.user_id = %userid%
	    INNER JOIN polygon_master pm
        ON st_within(v.sp_geometry, pm.sp_geometry)
        AND case when %SourcerefId% > 0 then pm.system_id = %SourcerefId% AND pm.entity_type = 'Network_Ticket' 
	   else 1=1 end ) as a USING UNIQUE system_id USING srid=4326"
		FILTER (%layerFilter% AND (%NetworkFilter%))
		VALIDATION
			'layerFilter' '.*'
			'NetworkFilter' '.*'		
			'userid' '.*'	
			'SourcerefId' '.*'
		END
		METADATA
			'ows_title' 'Building'
		END
		STATUS OFF
		LABELITEM 'label_column'
		GROUP 'Network'			
		CLASS
			NAME 'Surveyed Building' 	
			EXPRESSION ('[building_status]' = 'Surveyed')			
			STYLE
				SYMBOL [icon_path]
				SIZE 18			
			END
			LEADER
			  GRIDSTEP 6
			  MAXDISTANCE 10000
			  STYLE
				COLOR 200 100 100
				WIDTH 1
			  END
			END	
			LABEL 
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE
			END					
		END
		CLASS
			NAME 'Resurveyed Building' 	
			EXPRESSION ('[building_status]' = 'Resurveyed')			
			STYLE
				SYMBOL [icon_path]
				SIZE 18			
			END
			LEADER
			  GRIDSTEP 6
			  MAXDISTANCE 10000
			  STYLE
				COLOR 200 100 100
				WIDTH 1
			  END
			END	
			LABEL 
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE
			END					
		END
	END	
