	#=================================================POD ====
	LAYER
		NAME 'POD'
		TYPE POINT
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo 
		INCLUDE "datashare.inc"
		DATA "sp_geometry FROM ( SELECT v.*
    FROM vw_att_details_pod_map v
    INNER JOIN user_permission_area m 
        ON v.region_id = m.region_id 
        AND v.province_id = m.province_id 
        AND m.user_id = %userid%
    INNER JOIN polygon_master pm
        ON ST_Within(v.sp_geometry, pm.sp_geometry)
        AND (
            CASE 
                WHEN %SourcerefId% > 0 
                THEN (pm.system_id = %SourcerefId% AND pm.entity_type = 'Network_Ticket')
                ELSE TRUE 
            END
        )) as a USING UNIQUE system_id USING srid=4326"
		
		FILTER (%layerFilter% AND (%NetworkFilter%)) 
		VALIDATION
			'layerFilter' '.*'
			'NetworkFilter' '.*'		
			'userid' '.*'	
			'SourcerefId' '.*'
