	# ===================ROW======================================= 	
	LAYER 
		NAME 'ROW'		
		TYPE POLYGON
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		INCLUDE "datashare.inc"
		#PROCESSING "NATIVE_FILTER=%provinceFilter%"
		DATA "sp_geometry FROM (SELECT v.*
		FROM vw_att_details_row_map v
		INNER JOIN user_permission_area m 
        ON v.region_id = m.region_id 
        AND v.province_id = m.province_id 
        AND m.user_id = %userid%
	    INNER JOIN polygon_master pm
        ON st_within(v.sp_geometry, pm.sp_geometry)
        AND case when %SourcerefId% > 0 then pm.system_id = %SourcerefId% AND pm.entity_type = 'Network_Ticket' 
	   else 1=1 end     ) as a USING UNIQUE system_id USING srid=4326"
		FILTER (%NetworkFilter%) 
		VALIDATION
			'NetworkFilter' '.*'		
			'userid' '.*'
			'SourcerefId' '.*'	
		END
		
		METADATA
			'ows_title' 'ROW'
		END
		STATUS OFF
		GROUP 'Network'
		TRANSPARENCY 30
		PROJECTION
			'proj=longlat'  
			'datum=WGS84'
			'no_defs'
		END			
		
		CLASS
			NAME 'ROW' 
			TEXT "[row_text]"	
			STYLE
				WIDTH 1
				OUTLINECOLOR 0 0 0
				COLOR [color_code] 
			END
			LABEL 
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0				
				SIZE 8								
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE				
			END		
		END
	END
	
	
	# ================================== ROW Center Line ======================================== 
	LAYER
		NAME 'ROWL'
		TYPE LINE
		DUMP true
		TEMPLATE fooOnlyForWMSGetFeatureInfo
		#EXTENT 72.504366 18.900959 73.403214 19.320367
		INCLUDE "datashare.inc"
		DATA "center_line_geom FROM (SELECT v.*
		FROM vw_att_details_row_map v
		INNER JOIN user_permission_area m 
        ON v.region_id = m.region_id 
        AND v.province_id = m.province_id 
        AND m.user_id = %userid%
	    INNER JOIN polygon_master pm
        ON st_within(v.sp_geometry, pm.sp_geometry)
        AND case when %SourcerefId% > 0 then pm.system_id = %SourcerefId% AND pm.entity_type = 'Network_Ticket' 
	   else 1=1 end ) as a USING UNIQUE system_id USING srid=4326"
		FILTER (%NetworkFilter%) 
		VALIDATION
			'NetworkFilter' '.*'		
			'userid' '.*'
			'SourcerefId' '.*'
		END
		METADATA
			'ows_title' 'CABLE'
		END
		STATUS OFF
		GROUP 'Network1'
		TRANSPARENCY 100
		LABELITEM 'label_column'
		PROJECTION
			'proj=longlat'
			'datum=WGS84'
			'no_defs'
		END		

		CLASS 
			NAME "Cable"						
		     STYLE
				WIDTH 2
				COLOR 255 0 0				                						
			END
			LABEL 
			    OUTLINEWIDTH 5
				OUTLINECOLOR 255 255 255
				FONT arial
				TYPE truetype
				COLOR 0 0 0				
				SIZE 8
				STYLE
					GEOMTRANSFORM 'labelpoly'
					COLOR 255 0 0  # background rect.
				END
				STYLE
					GEOMTRANSFORM 'labelunderline'
					COLOR          255 0 0     # underline
					OFFSET 0 -1 # with some offset
				END
				OFFSET 0 0
				ANTIALIAS TRUE
				POSITION CC
				ANGLE AUTO
				FORCE FALSE
				PARTIALS FALSE
			END			
		END			
	END
	
