        ON v.region_id = m.region_id 
        AND v.province_id = m.province_id 
        AND m.user_id = %userid%
	    INNER JOIN polygon_master pm
        ON st_within(v.sp_geometry, pm.sp_geometry)
        AND case when %SourcerefId% > 0 then pm.system_id = %SourcerefId% AND pm.entity_type = 'Network_Ticket' 
	   else 1=1 end ) as a USING UNIQUE system_id USING srid=4326"
		FILTER (%layerFilter% AND (%NetworkFilter%))
		VALIDATION
			'layerFilter' '.*'
			'NetworkFilter' '.*'		
			'userid' '.*'	
			'SourcerefId' '.*'	
		END
		METADATA
			'ows_title' 'Cabinet'
		END
		STATUS OFF
		LABELITEM 'label_column'
		GROUP 'Network'		
		CLASS
			NAME 'Cabinet'
            EXPRESSION ('[network_status]'  eq 'P')  			
			STYLE
				SYMBOL [icon_path]
				SIZE 18			
			END
			LEADER
			  GRIDSTEP 6
			  MAXDISTANCE 10000
			  STYLE
				COLOR 200 100 100
				WIDTH 1
			  END
			END	
            LABEL 
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE	
            END			
		END
		CLASS
			NAME 'Cabinet'
            EXPRESSION ('[network_status]'  eq 'A')  			
			STYLE
				SYMBOL [icon_path]
				SIZE 18			
			END
			LEADER
			  GRIDSTEP 6
			  MAXDISTANCE 10000
			  STYLE
				COLOR 200 100 100
				WIDTH 1
			  END
			END	
            LABEL 
				COLOR  255 0 0  		
				FONT "arial"
				TYPE truetype
				SIZE 8
				POSITION AUTO
				PARTIALS FALSE	
            END			
		END
